import cv2
import numpy as np
import os
from flask import Flask, request, jsonify
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
import pickle
import face_recognition

app = Flask(__name__)

class FacialRecognitionAPI:
    def __init__(self):
        self.model = SVC(kernel='linear', probability=True)
        self.label_encoder = LabelEncoder()
        self.known_faces = []
        self.known_names = []
        self.is_trained = False
        
    def extract_face_features(self, image_path):
        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image)
        if len(face_locations) == 0:
            return None
        face_encodings = face_recognition.face_encodings(image, face_locations)
        return face_encodings[0] if face_encodings else None
    
    def train_model(self, dataset_path):
        faces = []
        names = []
        
        for person_name in os.listdir(dataset_path):
            person_folder = os.path.join(dataset_path, person_name)
            if not os.path.isdir(person_folder):
                continue
                
            for image_file in os.listdir(person_folder):
                if image_file.lower().endswith(('.png', '.jpg', '.jpeg')):
                    image_path = os.path.join(person_folder, image_file)
                    face_encoding = self.extract_face_features(image_path)
                    if face_encoding is not None:
                        faces.append(face_encoding)
                        names.append(person_name)
        
        if len(faces) == 0:
            raise ValueError("No faces found in dataset")
            
        self.known_faces = np.array(faces)
        self.known_names = np.array(names)
        
        # Encode labels
        encoded_labels = self.label_encoder.fit_transform(names)
        
        # Train SVM model
        self.model.fit(faces, encoded_labels)
        self.is_trained = True
        
        # Save model
        self.save_model("facial_recognition_model.pkl")
        
    def save_model(self, filename):
        model_data = {
            'model': self.model,
            'label_encoder': self.label_encoder,
            'known_faces': self.known_faces,
            'known_names': self.known_names
        }
        with open(filename, 'wb') as f:
            pickle.dump(model_data, f)
            
    def load_model(self, filename):
        with open(filename, 'rb') as f:
            model_data = pickle.load(f)
            
        self.model = model_data['model']
        self.label_encoder = model_data['label_encoder']
        self.known_faces = model_data['known_faces']
        self.known_names = model_data['known_names']
        self.is_trained = True
        
    def recognize_face(self, image_path):
        if not self.is_trained:
            raise ValueError("Model not trained yet")
            
        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image)
        face_encodings = face_recognition.face_encodings(image, face_locations)
        
        results = []
        
        for face_encoding in face_encodings:
            # Get prediction probabilities
            probabilities = self.model.predict_proba([face_encoding])[0]
            predicted_class = self.model.predict([face_encoding])[0]
            predicted_name = self.label_encoder.inverse_transform([predicted_class])[0]
            
            # Create probability distribution
            prob_dict = {}
            for i, name in enumerate(self.label_encoder.classes_):
                prob_dict[name] = float(probabilities[i])
                
            results.append({
                'face_location': face_locations[0],
                'predicted_name': predicted_name,
                'confidence': float(probabilities[predicted_class]),
                'probability_distribution': prob_dict
            })
            
        return results

# Initialize API
face_api = FacialRecognitionAPI()

@app.route('/train', methods=['POST'])
def train_model():
    try:
        dataset_path = request.json.get('dataset_path')
        if not dataset_path:
            return jsonify({'error': 'Dataset path required'}), 400
            
        face_api.train_model(dataset_path)
        return jsonify({'status': 'success', 'message': 'Model trained successfully'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/recognize', methods=['POST'])
def recognize_face():
    try:
        if not request.files:
            return jsonify({'error': 'No image provided'}), 400
            
        file = request.files['image']
        if not file:
            return jsonify({'error': 'No image provided'}), 400
            
        # Save temporary image
        temp_path = 'temp_image.jpg'
        file.save(temp_path)
        
        # Recognize face
        results = face_api.recognize_face(temp_path)
        
        # Clean up
        os.remove(temp_path)
        
        return jsonify({'results': results})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/status', methods=['GET'])
def get_status():
    return jsonify({'trained': face_api.is_trained})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)